[data-moduix-theme='soft'] {
  color-scheme: light;
  --background: oklch(0.985 0.012 320);
  --foreground: oklch(0.225 0.024 315);
  --card: oklch(0.998 0.004 320);
  --card-foreground: oklch(0.225 0.024 315);
  --popover: oklch(0.998 0.004 320);
  --popover-foreground: oklch(0.225 0.024 315);
  --primary: oklch(0.54 0.18 305);
  --primary-foreground: oklch(0.99 0.004 320);
  --secondary: oklch(0.958 0.018 320);
  --secondary-foreground: oklch(0.3 0.04 310);
  --muted: oklch(0.95 0.016 320);
  --muted-foreground: oklch(0.5 0.035 315);
  --accent: oklch(0.92 0.04 315);
  --accent-foreground: oklch(0.29 0.05 305);
  --border: oklch(0.88 0.025 320);
  --input: oklch(0.84 0.03 320);
  --ring: oklch(0.61 0.15 305);
  --overlay: oklch(0.22 0.035 310 / 0.22);
  --overlay-foreground: oklch(0.22 0.035 310 / 0.08);
  --sidebar: oklch(0.975 0.014 320);
  --sidebar-foreground: oklch(0.225 0.024 315);
  --sidebar-primary: oklch(0.54 0.18 305);
  --sidebar-primary-foreground: oklch(0.99 0.004 320);
  --sidebar-accent: oklch(0.92 0.04 315);
  --sidebar-accent-foreground: oklch(0.29 0.05 305);
  --sidebar-border: oklch(0.88 0.025 320);
  --sidebar-ring: oklch(0.61 0.15 305);
  --radius: 1rem;
  --spacing-2: 9px;
  --spacing-3: 14px;
  --spacing-4: 18px;
  --spacing-5: 22px;
  --spacing-6: 28px;
  --spacing-8: 36px;
  --spacing-10: 44px;
  --size-xs: 26px;
  --size-sm: 34px;
  --size-md: 40px;
  --size-lg: 44px;
  --size-xl: 52px;
  --shadow-sm: 0 2px 6px rgb(97 35 107 / 0.08);
  --shadow-md: 0 8px 18px rgb(97 35 107 / 0.12);
  --shadow-lg: 0 18px 38px rgb(97 35 107 / 0.16);

  .dark,
  &.dark {
    color-scheme: dark;
    --background: oklch(0.17 0.018 315);
    --foreground: oklch(0.972 0.006 320);
    --card: oklch(0.22 0.022 315);
    --card-foreground: oklch(0.972 0.006 320);
    --popover: oklch(0.22 0.022 315);
    --popover-foreground: oklch(0.972 0.006 320);
    --primary: oklch(0.78 0.13 305);
    --primary-foreground: oklch(0.23 0.026 315);
    --secondary: oklch(0.285 0.03 315);
    --secondary-foreground: oklch(0.972 0.006 320);
    --muted: oklch(0.275 0.026 315);
    --muted-foreground: oklch(0.74 0.03 320);
    --accent: oklch(0.34 0.06 310);
    --accent-foreground: oklch(0.972 0.006 320);
    --border: oklch(0.76 0.035 320 / 0.24);
    --input: oklch(0.76 0.035 320 / 0.3);
    --ring: oklch(0.74 0.11 305);
    --overlay: oklch(0.1 0.02 315 / 0.8);
    --overlay-foreground: oklch(0.972 0.006 320 / 0.1);
    --sidebar: oklch(0.2 0.022 315);
    --sidebar-foreground: oklch(0.972 0.006 320);
    --sidebar-primary: oklch(0.78 0.13 305);
    --sidebar-primary-foreground: oklch(0.23 0.026 315);
    --sidebar-accent: oklch(0.34 0.06 310);
    --sidebar-accent-foreground: oklch(0.972 0.006 320);
    --sidebar-border: oklch(0.76 0.035 320 / 0.24);
    --sidebar-ring: oklch(0.74 0.11 305);
  }
}
